@@ -75,22 +75,44 @@ export class InputRouter {
         Shell.util_set_hidden_from_pick(actor, false);
         actor.opacity = 255;

-        // Position near the stamp
+        // Position the real window NEXT TO the stamp (not on top),
+        // so the stamp remains clickable for restore/un-minimize.
+        // Try left of stamp first, then right, then above, then below.
         const frameRect = metaWindow.get_frame_rect();
         const [stampX, stampY] = container.get_transformed_position();
         const monGeo = global.display.get_monitor_geometry(metaWindow.get_monitor());
+        const gap = 4;

-        let newX = Math.round(stampX);
-        let newY = Math.round(stampY - frameRect.height + container.height);
-
-        if (newX + frameRect.width > monGeo.x + monGeo.width)
-            newX = monGeo.x + monGeo.width - frameRect.width;
-        if (newX < monGeo.x)
-            newX = monGeo.x;
-        if (newY < monGeo.y)
-            newY = monGeo.y;
-        if (newY + frameRect.height > monGeo.y + monGeo.height)
-            newY = monGeo.y + monGeo.height - frameRect.height;
+        let newX, newY;
+
+        // Try left of stamp
+        newX = stampX - frameRect.width - gap;
+        newY = stampY + container.height - frameRect.height;
+        if (newY < monGeo.y) newY = monGeo.y;
+
+        // If doesn't fit left, try right
+        if (newX < monGeo.x) {
+            newX = stampX + container.width + gap;
+            newY = stampY + container.height - frameRect.height;
+            if (newY < monGeo.y) newY = monGeo.y;
+        }
+
+        // If doesn't fit right either, go above
+        if (newX + frameRect.width > monGeo.x + monGeo.width) {
+            newX = stampX;
+            newY = stampY - frameRect.height - gap;
+            if (newX + frameRect.width > monGeo.x + monGeo.width)
+                newX = monGeo.x + monGeo.width - frameRect.width;
+        }
+
+        // Last resort: below
+        if (newY < monGeo.y) {
+            newY = stampY + container.height + gap;
+        }
+
+        // Final clamp
+        newX = Math.max(monGeo.x, Math.min(newX, monGeo.x + monGeo.width - frameRect.width));
+        newY = Math.max(monGeo.y, Math.min(newY, monGeo.y + monGeo.height - frameRect.height));

         metaWindow.move_frame(true, newX, newY);
         metaWindow.activate(global.get_current_time());
